// FILE: The three most common Android perf fixes, in one place

// 1. JANK FIX — network on main thread was blocking frames
// BAD:
fun onCreate(...) {
  val json = URL(url).readText()   // 500 ms — 30 frames dropped
  render(json)
}
// GOOD:
fun onCreate(...) {
  lifecycleScope.launch {
    val json = withContext(Dispatchers.IO) { URL(url).readText() }
    render(json)
  }
}

// 2. LEAK FIX — Activity Context held in a singleton
// BAD:
object AppSingleton { lateinit var ctx: Context }   // if you pass an Activity, you leak it
// GOOD:
class App : Application() {
  override fun onCreate() { super.onCreate(); AppSingleton.ctx = applicationContext }
}
// Even better: don't store contexts in singletons; inject with Hilt.

// 3. STARTUP FIX — heavy Application.onCreate
// BAD:
class App : Application() {
  override fun onCreate() {
    super.onCreate()
    Analytics.init(this)              // 200 ms
    CrashReporter.init(this)          // 100 ms
    ImageLoader.warmCache(this)       // 300 ms — user's screen is still blank!
  }
}
// GOOD — defer non-critical:
class App : Application() {
  override fun onCreate() {
    super.onCreate()
    CrashReporter.init(this)          // critical
    // Defer the rest:
    Handler(Looper.getMainLooper()).post {
      Analytics.init(this)
      ImageLoader.warmCache(this)
    }
  }
}
// EVEN BETTER — use the App Startup library to declare initializers with priorities,
// generate Baseline Profiles to AOT-compile hot paths.
